payload.raw:
{
  "layout": "timeline",
  "title": "创新设计",
  "events": [
    {
      "date": "第1–2月",
      "title": "材料与硬件攻坚",
      "description": "完成柔性传感器微结构设计、液态金属-聚氨酯复合材料制备及信号标定，构建0.1mm级空间分辨率的混合传感架构，奠定高灵敏度（应变系数>150）与低迟滞基础。"
    },
    {
      "date": "第3月",
      "title": "算法开发与融合协议构建",
      "description": "开发分层CNN-LSTM手势识别模型，结合自适应滑动窗口分割与噪声抑制模块，实现实测准确率>98.2%；同步建立视觉-触觉-听觉统一时空对齐协议，提升跨设备部署效率60%。"
    },
    {
      "date": "第4月",
      "title": "系统集成与反馈闭环搭建",
      "description": "完成软硬件联调，嵌入微型电磁致动器阵列与半导体温控模块，实现压力/温度微秒级调控；集成多模态交互协议栈，构建感知-意图-反馈闭环系统。"
    },
    {
      "date": "第5–6月",
      "title": "多场景验证与体验优化",
      "description": "依托H-Box全息舱、李未可眼镜等平台，在工业远程操控与虚拟实训场景开展压力测试，通过用户反馈迭代优化，形成可复用的元宇宙交互标准接口。"
    }
  ]
}

